question:
What is the outcome of the following code?
```cpp
class Base {
public:
    virtual void foo() { cout << "Base"; }
};
class Derived : public Base {
public:
    void foo() override { cout << "Derived"; }
};
int main() {
    Derived d;
    Base b = d; // Object slicing occurs here
    b.foo();
    return 0;
}
```
